noteContentFormat:
{% set baseUrl = url|slice:0,-1 %}
{% set albumUrls = selector:ol.music-grid li.music-grid-item a?href %}
{% set albumLisHtml = selectorHtml:ol.music-grid li.music-grid-item %}
- [ ] ttt [{{meta:property:og:title}}]({{url}}) ➕ {{date|date:"YYYY-MM-DD"}}
{% for liHtml in albumLisHtml %}
{% set albumName = liHtml|remove_html:"img"|markdown|strip_md|trim %}
- [ ] ttt [{{albumName}}]({{baseUrl}}{{albumUrls[loop.index0]}}) ➕ {{date|date:"YYYY-MM-DD"}}
{% endfor %}
